field.text:
checkpoints("cooking_session", "Plan and prepare a cooking session", [
  { id: "ask_preferences", instructions: "Find out what the user wants to cook", outputSchema: { preferences: { type: "string" } } },
  { id: "load_knowledge", instructions: "Load relevant cooking and nutrition knowledge", outputSchema: { loaded: { type: "boolean" } } },
  { id: "suggest_recipe", instructions: "Provide recipe suggestions based on preferences", outputSchema: { suggested: { type: "boolean" } } }
])

var preferences = await ask(<RequestForm title="What would you like to cook?" fields={[
  { name: "cuisine", label: "Cuisine Preference", type: "select", options: ["Italian", "Japanese", "Mexican", "Other"] },
  { name: "dietary", label: "Dietary Restrictions", type: "multiselect", options: ["Vegetarian", "Gluten-Free", "Dairy-Free"] },
  { name: "technique", label: "Cooking Method", type: "multiselect", options: ["Sauté", "Braise", "Grill", "Other"] }
]} />)

checkpoint("cooking_session", "ask_preferences", { preferences: "italian cuisine, no dietary restrictions" })

var docs = loadKnowledge({
  "cooking": {
    "cuisine": { "type": { "italian": true } },
    "dietary": { "restriction": { "vegetarian": true, "gluten-free": true, "dairy-free": true } },
    "technique": { "method": { "saute": true, "braise": true, "grill": true } }
  },
  "nutrition": {
    "macronutrients": { "type": { "protein": true, "carbohydrates": true, "fats": true } },
    "meal-planning": { "strategy": { "plate-method": true, "batch-prep": true, "calorie-tracking": true } }
  }
})

checkpoints("cooking_session", "Plan and prepare a cooking session", [
  { id: "ask_preferences", instructions: "Find out what the user wants to cook", outputSchema: { preferences: { type: "string" } } },
  { id: "load_knowledge", instructions: "Load relevant cooking and nutrition knowledge", outputSchema: { loaded: { type: "boolean" } } },
  { id: "suggest_recipe", instructions: "Provide recipe suggestions based on preferences", outputSchema: { suggested: { type: "boolean" } } }
